1	/**
2	 * CommandId idempotency store.
3	 *
4	 * The WS `control` frame and HTTP `POST /api/workflows/:id/control` both carry
5	 * a client-generated `commandId` (uuid). A repeated id within 5 minutes MUST
6	 * return the previous response without re-executing the action.
7	 *
8	 * Implementation: in-memory Map with explicit TTL. Entries older than TTL_MS
9	 * are evicted lazily on each lookup. No persistence — idempotency window
10	 * resets on server restart, which is acceptable per the spec (5-min window
11	 * is a client-side safety net for network retries, not a durability contract).
12	 */
13	
14	/** TTL for idempotency entries: 5 minutes. */
15	export const IDEMPOTENCY_TTL_MS = 5 * 60 * 1_000;
16	
17	export interface IdempotencyEntry {
18	  /** Cached response to return on duplicate commandId. */
19	  response: unknown;
20	  /** Absolute wall-clock expiry (ms since epoch). */
21	  expiresAt: number;
22	}
23	
24	export class IdempotencyStore {
25	  private readonly entries = new Map<string, IdempotencyEntry>();
26	
27	  /**
28	   * Returns the cached response for commandId if it exists and has not yet
29	   * expired. Returns undefined if the entry is absent or expired (and evicts
30	   * stale entries on access so they don't accumulate).
31	   */
32	  get(commandId: string): unknown | undefined {
33	    const entry = this.entries.get(commandId);
34	    if (!entry) return undefined;
35	    if (Date.now() > entry.expiresAt) {
36	      this.entries.delete(commandId);
37	      return undefined;
38	    }
39	    return entry.response;
40	  }
41	
42	  /**
43	   * Records response for commandId. Subsequent calls to get() within
44	   * IDEMPOTENCY_TTL_MS will return this response without re-executing the
45	   * action. Calling set() again with the same id overwrites the entry.
46	   */
47	  set(commandId: string, response: unknown): void {
48	    this.entries.set(commandId, {
49	      response,
50	      expiresAt: Date.now() + IDEMPOTENCY_TTL_MS,
51	    });
52	  }
53	
54	  /** Evicts all entries whose TTL has elapsed. Useful for periodic GC. */
55	  evictExpired(): void {
56	    const now = Date.now();
57	    for (const [id, entry] of this.entries) {
58	      if (now > entry.expiresAt) {
59	        this.entries.delete(id);
60	      }
61	    }
62	  }
63	
64	  /** Current number of live (non-expired) entries. For testing / metrics. */
65	  get size(): number {
66	    this.evictExpired();
67	    return this.entries.size;
68	  }
69	}
