81	/**
82	 * Result returned by AckAttentionFn to the API layer.
83	 * The callback owns both the read and the write for the ack operation so that
84	 * the API layer has no SQLite write path (RC-3).
85	 */
86	export type AckAttentionResult =
87	  | { status: 'acknowledged'; id: number }
88	  | { status: 'already_acknowledged'; id: number }
89	  | { status: 'not_found' };
