91	/**
92	 * Callback that handles POST /api/workflows/:id/attention/:attentionId/ack.
93	 * Implementations must: verify the attention item exists and belongs to
94	 * workflowId, check acknowledged_at, write acknowledged_at = datetime('now')
95	 * if not already set, and return the appropriate result.
96	 *
97	 * The write MUST NOT happen inside the API layer (RC-3). Callers inject this
98	 * callback so the actual SQLite write lives in the pipeline engine layer.
99	 */
100	export type AckAttentionFn = (workflowId: string, attentionId: number) => AckAttentionResult;
101	
102	/**
103	 * Optional callbacks injected into the server at creation time.
104	 * These allow the API layer to delegate writes to the pipeline engine layer
105	 * without the API module having any SQLite write path (RC-3).
106	 */
107	export interface ServerCallbacks {
108	  /**
109	   * Called when a client POSTs to
110	   * /api/workflows/:id/attention/:attentionId/ack.
111	   * If omitted, the endpoint returns 501 Not Implemented.
112	   */
113	  ackAttention?: AckAttentionFn;
114	}
