116	/**
117	 * Creates and configures the Fastify server.
118	 *
119	 * Callers must await fastify.listen(...) to start accepting connections.
120	 * The returned instance's .server.address() gives the bound port.
121	 *
122	 * @param db         DbPool opened by the caller.
123	 * @param callbacks  Optional injected handlers for write operations (RC-3).
124	 */
125	export async function createServer(db: DbPool, callbacks: ServerCallbacks = {}): Promise<ServerHandle> {
126	  const fastify = Fastify({ logger: false });
127	
128	  // Shared state for the WS layer.
129	  const seqStore = new SessionSeqStore();
130	  const backfillBuffer = new BackfillBuffer();
131	  const idempotency = new IdempotencyStore();
132	
133	  // Register WebSocket plugin.
134	  await fastify.register(fastifyWebsocket);
135	
136	  // WebSocket route at /stream (§4 Lifecycle).
137	  // Registered directly on the root fastify instance so it inherits the
138	  // @fastify/websocket plugin decoration without sub-plugin scoping issues.
139	  const wsHandler = createWsHandler({ db, idempotency, seqStore, backfillBuffer });
140	  fastify.get('/stream', { websocket: true }, (connection: SocketStream) => {
141	    wsHandler(connection.socket);
142	  });
143	
144	  // -------------------------------------------------------------------------
145	  // §7 HTTP companion endpoints
146	  // All read from db.reader() — no workflow/item state writes.
147	  // -------------------------------------------------------------------------
148	
149	  // GET /api/workflows?status=&q=&before=&limit=
150	  // Keyset pagination (D47). Ordered by created_at DESC.
151	  fastify.get(
152	    '/api/workflows',
153	    async (req: FastifyRequest, reply: FastifyReply) => {
154	      const qs = req.query as Record<string, string | undefined>;
155	      const limitRaw = parseInt(qs.limit ?? '20', 10);
156	      if (!isFinite(limitRaw) || limitRaw < 1) return badRequest(reply, 'limit must be a positive integer');
157	      const limit = Math.min(limitRaw, 100);
158	
159	      let sql = 'SELECT id, name, status, current_stage, created_at, updated_at FROM workflows WHERE 1=1';
160	      const params: unknown[] = [];
161	
162	      if (qs.status) {
163	        sql += ' AND status = ?';
164	        params.push(qs.status);
165	      }
166	      if (qs.q) {
167	        sql += ' AND name LIKE ?';
168	        params.push(`%${qs.q}%`);
169	      }
170	      if (qs.before) {
171	        sql += ' AND created_at < ?';
172	        params.push(qs.before);
173	      }
174	      sql += ` ORDER BY created_at DESC LIMIT ${limit + 1}`;
175	
176	      const rows = db.reader().prepare(sql).all(...params) as WorkflowRow[];
177	      const hasMore = rows.length > limit;
178	      const workflows = hasMore ? rows.slice(0, limit) : rows;
179	
180	      return reply.send({
181	        workflows,
182	        hasMore,
183	        nextBefore: hasMore ? workflows[workflows.length - 1].created_at : null,
184	      });
185	    },
186	  );
187	
188	  // GET /api/workflows/:id/timeline
189	  // Merged SQLite events + JSONL (§Obs, D34).
190	  fastify.get(
191	    '/api/workflows/:id/timeline',
192	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
193	      const { id } = req.params;
194	      const reader = db.reader();
195	
196	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
197	      if (!wf) return notFound(reply, 'workflow not found');
198	
199	      const events = reader
200	        .prepare(
201	          'SELECT id, ts, workflow_id, item_id, session_id, stage, phase, attempt, event_type, level, message, extra FROM events WHERE workflow_id = ? ORDER BY ts, id',
202	        )
203	        .all(id) as Array<{
204	          id: number;
205	          ts: string;
206	          workflow_id: string;
207	          item_id: string | null;
208	          session_id: string | null;
209	          stage: string | null;
210	          phase: string | null;
211	          attempt: number | null;
212	          event_type: string;
213	          level: string;
214	          message: string;
215	          extra: string | null;
216	        }>;
217	
218	      return reply.send({
219	        workflowId: id,
220	        events: events.map((e) => ({
221	          ...e,
222	          extra: e.extra ? (() => { try { return JSON.parse(e.extra!); } catch { return e.extra; } })() : null,
223	        })),
224	      });
225	    },
226	  );
227	
228	  // GET /api/sessions/:id/log?sinceSeq=&limit=
229	  // Paged stream-json fetch (D48a). Reads from JSONL file via readLogPage.
230	  fastify.get(
231	    '/api/sessions/:id/log',
232	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
233	      const { id } = req.params;
234	      const qs = req.query as Record<string, string | undefined>;
235	
236	      const sinceSeqRaw = qs.sinceSeq !== undefined ? parseInt(qs.sinceSeq, 10) : 0;
237	      const limitRaw = qs.limit !== undefined ? parseInt(qs.limit, 10) : 100;
238	
239	      if (!isFinite(sinceSeqRaw) || sinceSeqRaw < 0) return badRequest(reply, 'sinceSeq must be a non-negative integer');
240	      if (!isFinite(limitRaw) || limitRaw < 1) return badRequest(reply, 'limit must be a positive integer');
241	
242	      const sinceSeq = Math.max(0, sinceSeqRaw);
243	      const limit = Math.max(1, limitRaw);
244	
245	      const reader = db.reader();
246	      const row = reader
247	        .prepare('SELECT session_log_path FROM sessions WHERE id = ?')
248	        .get(id) as { session_log_path: string | null } | undefined;
249	
250	      if (!row) return notFound(reply, 'session not found');
251	
252	      if (!row.session_log_path) {
253	        return reply.send({ entries: [], nextSeq: sinceSeq, hasMore: false });
254	      }
255	
256	      const page = await readLogPage(row.session_log_path, sinceSeq, limit);
257	      if (!page) {
258	        return reply.send({ entries: [], nextSeq: sinceSeq, hasMore: false });
259	      }
260	
261	      return reply.send(page);
262	    },
263	  );
264	
265	  // GET /api/workflows/:id/usage?groupBy=feature|phase|profile|session
266	  // Token aggregates per groupBy dimension.
267	  fastify.get(
268	    '/api/workflows/:id/usage',
269	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
270	      const { id } = req.params;
271	      const qs = req.query as Record<string, string | undefined>;
272	      const groupBy = qs.groupBy ?? 'session';
273	
274	      const validGroupBy = ['feature', 'phase', 'profile', 'session'];
275	      if (!validGroupBy.includes(groupBy)) {
276	        return badRequest(reply, `groupBy must be one of: ${validGroupBy.join(', ')}`);
277	      }
278	
279	      const reader = db.reader();
280	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
281	      if (!wf) return notFound(reply, 'workflow not found');
282	
283	      // Map groupBy dimension to SQLite column.
284	      const groupCol: Record<string, string> = {
285	        feature: 'item_id',
286	        phase: 'phase',
287	        profile: 'agent_profile',
288	        session: 'id',
289	      };
290	      const col = groupCol[groupBy];
291	
292	      const rows = reader
293	        .prepare(
294	          `SELECT ${col} AS dimension,
295	                  SUM(input_tokens) AS input_tokens,
296	                  SUM(output_tokens) AS output_tokens,
297	                  SUM(cache_creation_input_tokens) AS cache_creation_input_tokens,
298	                  SUM(cache_read_input_tokens) AS cache_read_input_tokens,
299	                  COUNT(*) AS session_count
300	           FROM sessions
301	           WHERE workflow_id = ?
302	           GROUP BY ${col}
303	           ORDER BY input_tokens DESC`,
304	        )
305	        .all(id);
306	
307	      return reply.send({ workflowId: id, groupBy, rows });
308	    },
309	  );
310	
311	  // GET /api/workflows/:id/usage/timeseries?bucket=hour|day
312	  // Usage timeseries bucketed by hour or day.
313	  fastify.get(
314	    '/api/workflows/:id/usage/timeseries',
315	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
316	      const { id } = req.params;
317	      const qs = req.query as Record<string, string | undefined>;
318	      const bucket = qs.bucket ?? 'hour';
319	
320	      if (bucket !== 'hour' && bucket !== 'day') {
321	        return badRequest(reply, 'bucket must be hour or day');
322	      }
323	
324	      const reader = db.reader();
325	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
326	      if (!wf) return notFound(reply, 'workflow not found');
327	
328	      // SQLite strftime format for the requested bucket.
329	      const fmt = bucket === 'hour' ? '%Y-%m-%dT%H:00:00Z' : '%Y-%m-%dT00:00:00Z';
330	
331	      const rows = reader
332	        .prepare(
333	          `SELECT strftime('${fmt}', started_at) AS bucket,
334	                  SUM(input_tokens) AS input_tokens,
335	                  SUM(output_tokens) AS output_tokens,
336	                  SUM(cache_creation_input_tokens) AS cache_creation_input_tokens,
337	                  SUM(cache_read_input_tokens) AS cache_read_input_tokens,
338	                  COUNT(*) AS session_count
339	           FROM sessions
340	           WHERE workflow_id = ?
341	           GROUP BY bucket
342	           ORDER BY bucket ASC`,
343	        )
344	        .all(id);
345	
346	      return reply.send({ workflowId: id, bucket, rows });
347	    },
348	  );
349	
350	  // POST /api/workflows/:id/control
351	  // Idempotent manual control (mirrors WS control frame).
352	  fastify.post(
353	    '/api/workflows/:id/control',
354	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
355	      const { id } = req.params;
356	      const body = req.body as {
357	        commandId?: string;
358	        action?: string;
359	        itemId?: string;
360	        stageId?: string;
361	        extra?: unknown;
362	      } | null;
363	
364	      if (!body?.commandId) return badRequest(reply, 'commandId is required');
365	      if (!body.action) return badRequest(reply, 'action is required');
366	
367	      const reader = db.reader();
368	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
369	      if (!wf) return notFound(reply, 'workflow not found');
370	
371	      // Idempotency check (AC-4, RC: not by re-executing).
372	      const cached = idempotency.get(body.commandId);
373	      if (cached !== undefined) {
374	        return reply.status(200).send(cached);
375	      }
376	
377	      // Cache and return accepted response. Actual execution deferred to pipeline engine.
378	      const response = {
379	        status: 'accepted',
380	        commandId: body.commandId,
381	        workflowId: id,
382	        action: body.action,
383	      };
384	      idempotency.set(body.commandId, response);
385	
386	      return reply.status(202).send(response);
387	    },
388	  );
389	
390	  // POST /api/workflows/:id/attention/:attentionId/ack
391	  // Clear a pending attention item.
392	  // The write is delegated to callbacks.ackAttention (RC-3 — no writes in API layer).
393	  fastify.post(
394	    '/api/workflows/:id/attention/:attentionId/ack',
395	    async (
396	      req: FastifyRequest<{ Params: { id: string; attentionId: string } }>,
397	      reply: FastifyReply,
398	    ) => {
399	      const { id, attentionId } = req.params;
400	      const attId = parseInt(attentionId, 10);
401	      if (!isFinite(attId)) return badRequest(reply, 'attentionId must be an integer');
402	
403	      if (!callbacks.ackAttention) {
404	        return reply.status(501).send({ error: 'attention ack not configured' });
405	      }
406	
407	      // Verify the workflow exists using the read-only connection.
408	      const wf = db.reader().prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
409	      if (!wf) return notFound(reply, 'workflow not found');
410	
411	      // Delegate the pending_attention read + write to the injected callback
412	      // so that no SQLite write occurs inside the API layer (RC-3).
413	      const result = callbacks.ackAttention(id, attId);
414	      if (result.status === 'not_found') return notFound(reply, 'attention item not found');
415	      return reply.send(result);
416	    },
417	  );
418	
419	  return { fastify, state: { seqStore, backfillBuffer, idempotency } };
420	}
421	
422	// ---------------------------------------------------------------------------
423	// Convenience: listen with enforced 127.0.0.1 binding (AC-6, RC)
424	// ---------------------------------------------------------------------------
425	
426	/**
427	 * Creates the server and starts listening on 127.0.0.1. Throws if host is
428	 * anything other than '127.0.0.1' — no 0.0.0.0 bind path exists (D57).
429	 *
430	 * @returns The listening Fastify instance.
431	 */
432	export async function listenServer(
433	  db: DbPool,
434	  opts: ServerOptions = {},
435	  callbacks: ServerCallbacks = {},
436	): Promise<FastifyInstance> {
437	  const host = opts.host ?? '127.0.0.1';
438	  if (host !== '127.0.0.1') {
439	    throw new Error(`Server must bind to 127.0.0.1, not ${host} (D57)`);
440	  }
441	  const port = opts.port ?? 0;
442	
443	  const { fastify } = await createServer(db, callbacks);
444	  await fastify.listen({ host, port });
445	  return fastify;
446	}
