// ---------------------------------------------------------------------------
// Envelope types (§8)
// ---------------------------------------------------------------------------

export type ServerFrameType =
  | 'hello'
  | 'workflow.snapshot'
  | 'workflow.update'
  | 'workflow.index.update'
  | 'item.state'
  | 'item.data'
  | 'stage.started'
  | 'stage.complete'
  | 'session.started'
  | 'session.ended'
  | 'stream.text'
  | 'stream.thinking'
