function notFound(reply: FastifyReply, message = 'not found'): FastifyReply {
  return reply.status(404).send({ error: message });
}

// ---------------------------------------------------------------------------
// Snapshot helpers
// ---------------------------------------------------------------------------

interface WorkflowRow {
  id: string;
  name: string;
  status: string;
  current_stage: string | null;
  created_at: string;
  updated_at: string;
}

// ---------------------------------------------------------------------------
// Server factory
