64	// ---------------------------------------------------------------------------
65	// WsSession — buffered message queue (no race condition with hello frame)
66	// ---------------------------------------------------------------------------
67	
68	interface WsSession {
69	  /** Dequeues the next frame (buffered or awaited). */
70	  next(): Promise<Record<string, unknown>>;
71	  /** Serialises frame to JSON and sends. */
72	  send(frame: object): void;
73	  /** Sends raw string bytes (for testing malformed input). */
74	  sendRaw(data: string): void;
75	  close(): void;
76	  onClose(): Promise<{ code: number; reason: string }>;
77	}
78	
79	function connectWs(): Promise<WsSession> {
80	  return new Promise<WsSession>((resolve, reject) => {
81	    const ws = new WebSocket(wsUrl);
82	    const queue: Record<string, unknown>[] = [];
83	    const waiters: Array<[(m: Record<string, unknown>) => void, (e: Error) => void]> = [];
84	    let closed = false;
85	    const closeCallbacks: Array<(info: { code: number; reason: string }) => void> = [];
86	
87	    // Register 'message' BEFORE 'open' fires so hello is never dropped.
88	    ws.on('message', (data: Buffer | string) => {
89	      try {
90	        const msg = JSON.parse(data.toString()) as Record<string, unknown>;
91	        if (waiters.length > 0) {
92	          const [res] = waiters.shift()!;
93	          res(msg);
94	        } else {
95	          queue.push(msg);
96	        }
97	      } catch {
98	        // ignore non-JSON
99	      }
100	    });
101	
102	    ws.on('close', (code, reason) => {
103	      closed = true;
104	      const info = { code, reason: reason.toString() };
105	      for (const cb of closeCallbacks) cb(info);
106	      // Reject any pending waiters (socket closed before message).
107	      for (const [, rej] of waiters) {
108	        rej(new Error(`WS closed with code ${code} before expected message`));
109	      }
110	      waiters.length = 0;
111	    });
112	
113	    ws.once('open', () =>
114	      resolve({
115	        next: () => {
116	          if (queue.length > 0) return Promise.resolve(queue.shift()!);
117	          if (closed) return Promise.reject(new Error('WS already closed'));
118	          return new Promise<Record<string, unknown>>((res, rej) => {
119	            waiters.push([res, rej]);
120	          });
121	        },
122	        send: (frame: object) => ws.send(JSON.stringify(frame)),
123	        sendRaw: (data: string) => ws.send(data),
124	        close: () => ws.close(),
125	        onClose: () =>
126	          new Promise<{ code: number; reason: string }>((res) => {
127	            if (closed) res({ code: 0, reason: '' });
128	            else closeCallbacks.push(res);
129	          }),
130	      }),
131	    );
132	    ws.once('error', reject);
133	    ws.on('unexpected-response', (_req, res) => {
134	      reject(new Error(`Unexpected HTTP response: ${res.statusCode}`));
135	    });
136	  });
137	}
