63	// ---------------------------------------------------------------------------
64	// WsSession — buffered message queue (no race condition with hello frame)
65	// ---------------------------------------------------------------------------
66	
67	interface WsSession {
68	  /** Dequeues the next frame (buffered or awaited). */
69	  next(): Promise<Record<string, unknown>>;
69	  /** Serialises frame to JSON and sends. */
70	  send(frame: object): void;
71	  /** Sends raw string bytes (for testing malformed input). */
72	  sendRaw(data: string): void;
73	  close(): void;
74	  onClose(): Promise<{ code: number; reason: string }>;
75	}
76	
77	function connectWs(): Promise<WsSession> {
78	  return new Promise<WsSession>((resolve, reject) => {
79	    const ws = new WebSocket(wsUrl);
80	    const queue: Record<string, unknown>[] = [];
81	    const waiters: Array<[(m: Record<string, unknown>) => void, (e: Error) => void]> = [];
82	    let closed = false;
83	    const closeCallbacks: Array<(info: { code: number; reason: string }) => void> = [];
84	
85	    // Register 'message' BEFORE 'open' fires so hello is never dropped.
86	    ws.on('message', (data: Buffer | string) => {
87	      try {
87	        const msg = JSON.parse(data.toString()) as Record<string, unknown>;
88	        if (waiters.length > 0) {
89	          const [res] = waiters.shift()!;
90	          res(msg);
91	        } else {
92	          queue.push(msg);
93	        }
94	      } catch {
95	        // ignore non-JSON
96	      }
97	    });
98	
99	    ws.on('close', (code, reason) => {
100	      closed = true;
101	      const info = { code, reason: reason.toString() };
102	      for (const cb of closeCallbacks) cb(info);
103	      // Reject any pending waiters (socket closed before message).
103	      for (const [, rej] of waiters) {
104	        rej(new Error(`WS closed with code ${code} before expected message`));
105	      }
106	      waiters.length = 0;
107	    });
108	
109	    ws.once('open', () =>
110	      resolve({
111	        next: () => {
112	          if (queue.length > 0) return Promise.resolve(queue.shift()!);
113	          if (closed) return Promise.reject(new Error('WS already closed'));
114	          return new Promise<Record<string, unknown>>((res, rej) => {
114	            waiters.push([res, rej]);
115	          });
116	        },
117	        send: (frame: object) => ws.send(JSON.stringify(frame)),
118	        send: (data: string) => ws.send(data),
118	        close: () => ws.close(),
119	        onClose: () =>
120	          new Promise<{ code: number; reason: string }>((res) => {
120	            if (closed) res({ code: 0, reason: '' });
121	            else closeCallbacks.push(res);
122	          }),
123	      }),
124	    );
125	    ws.once('error', reject);
126	    ws.on('unexpected-response', (_req, res) => {
127	      reject(new Error(`Unexpected HTTP response: ${res.statusCode}`));
128	    });
129	  });
130	}
