    | "idle"
    | "creating"
    | "created"
    | "failed";
  prNumber?: number;
  prUrl?: string;
  prState?: "open" | "merged" | "closed";
  error?: string;
  lastCheckedAt?: string;
}

export interface PendingAttention {
  id: number;
  kind: string;
  payload: unknown;
  createdAt: string;
}
